{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMiNOerXJgXyIHumJ0GoLKf"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"colab":{"base_uri":"https://localhost:8080/","height":698},"id":"sJvVieM59TD9","outputId":"17a1ef62-84ee-4266-b2f2-6e7c3eeb3984"},"outputs":[{"output_type":"stream","name":"stdout","text":["Drive already mounted at /content/drive; to attempt to forcibly remount, call drive.mount(\"/content/drive\", force_remount=True).\n"]},{"output_type":"stream","name":"stderr","text":["/tmp/ipykernel_25386/1415599673.py:343: DeprecationWarning: The 'theme' parameter in the Blocks constructor will be removed in Gradio 6.0. You will need to pass 'theme' to Blocks.launch() instead.\n","  with gr.Blocks(css=css, theme=gr.themes.Soft(primary_hue=\"blue\", secondary_hue=\"indigo\")) as app:\n","/tmp/ipykernel_25386/1415599673.py:343: DeprecationWarning: The 'css' parameter in the Blocks constructor will be removed in Gradio 6.0. You will need to pass 'css' to Blocks.launch() instead.\n","  with gr.Blocks(css=css, theme=gr.themes.Soft(primary_hue=\"blue\", secondary_hue=\"indigo\")) as app:\n"]},{"output_type":"stream","name":"stdout","text":["Colab notebook detected. This cell will run indefinitely so that you can see errors and logs. To turn off, set debug=False in launch().\n","* Running on public URL: https://91e68196fddd120198.gradio.live\n","\n","This share link expires in 1 week. For free permanent hosting and GPU upgrades, run `gradio deploy` from the terminal in the working directory to deploy to Hugging Face Spaces (https://huggingface.co/spaces)\n"]},{"output_type":"display_data","data":{"text/plain":["<IPython.core.display.HTML object>"],"text/html":["<div><iframe src=\"https://91e68196fddd120198.gradio.live\" width=\"100%\" height=\"500\" allow=\"autoplay; camera; microphone; clipboard-read; clipboard-write;\" frameborder=\"0\" allowfullscreen></iframe></div>"]},"metadata":{}}],"source":["from google.colab import drive\n","drive.mount('/content/drive')\n","\n","import sqlite3\n","import pandas as pd\n","import gradio as gr\n","from datetime import datetime\n","\n","# =========================================================\n","# CONFIG\n","# =========================================================\n","DB_PATH = \"/content/drive/MyDrive/Colab Notebooks/BDs/tarefas.db\"\n","\n","# =========================================================\n","# BANCO\n","# =========================================================\n","def conectar():\n","    return sqlite3.connect(DB_PATH)\n","\n","def validar_estrutura():\n","    conn = conectar()\n","    cursor = conn.cursor()\n","    cursor.execute(\"PRAGMA table_info(tarefas)\")\n","    colunas = [c[1] for c in cursor.fetchall()]\n","    conn.close()\n","\n","    obrigatorias = [\"id\", \"titulo\", \"descricao\", \"prioridade\", \"status\", \"data_vencimento\"]\n","    faltantes = [c for c in obrigatorias if c not in colunas]\n","\n","    if faltantes:\n","        raise Exception(f\"A tabela tarefas não possui as colunas: {', '.join(faltantes)}\")\n","\n","# =========================================================\n","# DATA\n","# =========================================================\n","def para_banco(data_texto):\n","    if not data_texto or str(data_texto).strip() == \"\":\n","        return None\n","    try:\n","        return datetime.strptime(str(data_texto).strip(), \"%d/%m/%Y\").strftime(\"%Y-%m-%d\")\n","    except ValueError:\n","        raise ValueError(\"Data inválida. Use dd/mm/yyyy.\")\n","\n","def para_tela(data_texto):\n","    if not data_texto or str(data_texto).strip() == \"\":\n","        return \"\"\n","    try:\n","        return datetime.strptime(str(data_texto)[:10], \"%Y-%m-%d\").strftime(\"%d/%m/%Y\")\n","    except:\n","        return str(data_texto)\n","\n","# =========================================================\n","# CONSULTAS\n","# =========================================================\n","def listar_df():\n","    conn = conectar()\n","    df = pd.read_sql_query(\"\"\"\n","        SELECT\n","            id,\n","            titulo,\n","            descricao,\n","            prioridade,\n","            status,\n","            data_vencimento\n","        FROM tarefas\n","        ORDER BY\n","            CASE prioridade\n","                WHEN 'Alta' THEN 1\n","                WHEN 'Media' THEN 2\n","                WHEN 'Baixa' THEN 3\n","                ELSE 4\n","            END,\n","            CASE\n","                WHEN data_vencimento IS NULL OR data_vencimento = '' THEN 1\n","                ELSE 0\n","            END,\n","            data_vencimento,\n","            id DESC\n","    \"\"\", conn)\n","    conn.close()\n","\n","    if not df.empty:\n","        df[\"data_vencimento\"] = df[\"data_vencimento\"].apply(para_tela)\n","\n","    return df\n","\n","def resumo_cards():\n","    conn = conectar()\n","    cursor = conn.cursor()\n","\n","    cursor.execute(\"SELECT COUNT(*) FROM tarefas\")\n","    total = cursor.fetchone()[0]\n","\n","    cursor.execute(\"SELECT COUNT(*) FROM tarefas WHERE status = 'Pendente'\")\n","    pendentes = cursor.fetchone()[0]\n","\n","    cursor.execute(\"SELECT COUNT(*) FROM tarefas WHERE status = 'Em andamento'\")\n","    andamento = cursor.fetchone()[0]\n","\n","    cursor.execute(\"SELECT COUNT(*) FROM tarefas WHERE status = 'Concluida'\")\n","    concluidas = cursor.fetchone()[0]\n","\n","    conn.close()\n","\n","    html = f\"\"\"\n","    <div class=\"cards\">\n","        <div class=\"card card-total\">\n","            <div class=\"card-title\">Total</div>\n","            <div class=\"card-number\">{total}</div>\n","        </div>\n","        <div class=\"card card-pendente\">\n","            <div class=\"card-title\">Pendentes</div>\n","            <div class=\"card-number\">{pendentes}</div>\n","        </div>\n","        <div class=\"card card-andamento\">\n","            <div class=\"card-title\">Em andamento</div>\n","            <div class=\"card-number\">{andamento}</div>\n","        </div>\n","        <div class=\"card card-concluida\">\n","            <div class=\"card-title\">Concluídas</div>\n","            <div class=\"card-number\">{concluidas}</div>\n","        </div>\n","    </div>\n","    \"\"\"\n","    return html\n","\n","def obter_ids_tarefas():\n","    conn = conectar()\n","    cursor = conn.cursor()\n","    cursor.execute(\"SELECT id FROM tarefas ORDER BY id DESC\")\n","    ids = [str(l[0]) for l in cursor.fetchall()]\n","    conn.close()\n","    return ids\n","\n","def carregar_tarefa(id_tarefa):\n","    if not id_tarefa:\n","        return \"\", \"\", \"Media\", \"Pendente\", \"\"\n","\n","    conn = conectar()\n","    cursor = conn.cursor()\n","    cursor.execute(\"\"\"\n","        SELECT titulo, descricao, prioridade, status, data_vencimento\n","        FROM tarefas\n","        WHERE id = ?\n","    \"\"\", (id_tarefa,))\n","    linha = cursor.fetchone()\n","    conn.close()\n","\n","    if not linha:\n","        return \"\", \"\", \"Media\", \"Pendente\", \"\"\n","\n","    titulo, descricao, prioridade, status, data_vencimento = linha\n","    return (\n","        titulo or \"\",\n","        descricao or \"\",\n","        prioridade or \"Media\",\n","        status or \"Pendente\",\n","        para_tela(data_vencimento)\n","    )\n","\n","# =========================================================\n","# CRUD\n","# =========================================================\n","def inserir_tarefa(titulo, descricao, prioridade, status, data_vencimento):\n","    try:\n","        titulo = (titulo or \"\").strip()\n","        descricao = (descricao or \"\").strip()\n","\n","        if not titulo:\n","            return \"❌ O título é obrigatório.\", listar_df(), resumo_cards(), gr.update(choices=obter_ids_tarefas())\n","\n","        data_banco = para_banco(data_vencimento)\n","\n","        conn = conectar()\n","        cursor = conn.cursor()\n","        cursor.execute(\"\"\"\n","            INSERT INTO tarefas (titulo, descricao, prioridade, status, data_vencimento)\n","            VALUES (?, ?, ?, ?, ?)\n","        \"\"\", (\n","            titulo,\n","            descricao if descricao else None,\n","            prioridade,\n","            status,\n","            data_banco\n","        ))\n","        conn.commit()\n","        conn.close()\n","\n","        return \"✅ Tarefa criada com sucesso.\", listar_df(), resumo_cards(), gr.update(choices=obter_ids_tarefas())\n","    except Exception as e:\n","        return f\"❌ {e}\", listar_df(), resumo_cards(), gr.update(choices=obter_ids_tarefas())\n","\n","def atualizar_tarefa(id_tarefa, titulo, descricao, prioridade, status, data_vencimento):\n","    try:\n","        if not id_tarefa:\n","            return \"❌ Selecione uma tarefa para editar.\", listar_df(), resumo_cards(), gr.update()\n","\n","        titulo = (titulo or \"\").strip()\n","        descricao = (descricao or \"\").strip()\n","\n","        if not titulo:\n","            return \"❌ O título é obrigatório.\", listar_df(), resumo_cards(), gr.update()\n","\n","        data_banco = para_banco(data_vencimento)\n","\n","        conn = conectar()\n","        cursor = conn.cursor()\n","        cursor.execute(\"\"\"\n","            UPDATE tarefas\n","            SET titulo = ?, descricao = ?, prioridade = ?, status = ?, data_vencimento = ?\n","            WHERE id = ?\n","        \"\"\", (\n","            titulo,\n","            descricao if descricao else None,\n","            prioridade,\n","            status,\n","            data_banco,\n","            id_tarefa\n","        ))\n","        conn.commit()\n","        conn.close()\n","\n","        return \"✅ Tarefa atualizada com sucesso.\", listar_df(), resumo_cards(), gr.update(choices=obter_ids_tarefas(), value=str(id_tarefa))\n","    except Exception as e:\n","        return f\"❌ {e}\", listar_df(), resumo_cards(), gr.update()\n","\n","def excluir_tarefa(id_tarefa):\n","    try:\n","        if not id_tarefa:\n","            return \"❌ Selecione uma tarefa para excluir.\", listar_df(), resumo_cards(), gr.update(choices=obter_ids_tarefas(), value=None)\n","\n","        conn = conectar()\n","        cursor = conn.cursor()\n","        cursor.execute(\"DELETE FROM tarefas WHERE id = ?\", (id_tarefa,))\n","        conn.commit()\n","        conn.close()\n","\n","        return \"🗑️ Tarefa excluída com sucesso.\", listar_df(), resumo_cards(), gr.update(choices=obter_ids_tarefas(), value=None)\n","    except Exception as e:\n","        return f\"❌ {e}\", listar_df(), resumo_cards(), gr.update(choices=obter_ids_tarefas())\n","\n","def limpar_form_novo():\n","    return \"\", \"\", \"Media\", \"Pendente\", \"\"\n","\n","def limpar_form_edicao():\n","    return None, \"\", \"\", \"Media\", \"Pendente\", \"\"\n","\n","def filtrar_tarefas(prioridade, status, texto):\n","    df = listar_df()\n","\n","    if prioridade and prioridade != \"Todas\":\n","        df = df[df[\"prioridade\"] == prioridade]\n","\n","    if status and status != \"Todos\":\n","        df = df[df[\"status\"] == status]\n","\n","    if texto and str(texto).strip():\n","        termo = str(texto).strip().lower()\n","        df = df[\n","            df[\"titulo\"].fillna(\"\").str.lower().str.contains(termo, na=False) |\n","            df[\"descricao\"].fillna(\"\").str.lower().str.contains(termo, na=False)\n","        ]\n","\n","    return df\n","\n","# =========================================================\n","# CSS\n","# =========================================================\n","css = \"\"\"\n",".gradio-container {\n","    background: linear-gradient(180deg, #f4f8ff 0%, #eef4ff 100%);\n","    font-family: 'Segoe UI', sans-serif;\n","}\n",".top-banner {\n","    background: linear-gradient(135deg, #0d47a1 0%, #1565c0 45%, #1e88e5 100%);\n","    padding: 22px 28px;\n","    border-radius: 18px;\n","    color: white;\n","    box-shadow: 0 10px 30px rgba(13, 71, 161, 0.18);\n","    margin-bottom: 12px;\n","}\n",".top-banner h1 {\n","    margin: 0;\n","    font-size: 30px;\n","    font-weight: 800;\n","}\n",".top-banner p {\n","    margin: 8px 0 0;\n","    opacity: 0.96;\n","    font-size: 15px;\n","}\n",".cards {\n","    display: grid;\n","    grid-template-columns: repeat(4, 1fr);\n","    gap: 14px;\n","    margin: 10px 0 18px 0;\n","}\n",".card {\n","    padding: 18px;\n","    border-radius: 18px;\n","    color: white;\n","    box-shadow: 0 8px 24px rgba(0,0,0,0.10);\n","}\n",".card-title {\n","    font-size: 14px;\n","    opacity: 0.95;\n","    margin-bottom: 6px;\n","}\n",".card-number {\n","    font-size: 30px;\n","    font-weight: 800;\n","}\n",".card-total { background: linear-gradient(135deg, #0d47a1, #1976d2); }\n",".card-pendente { background: linear-gradient(135deg, #5e35b1, #7e57c2); }\n",".card-andamento { background: linear-gradient(135deg, #00838f, #00acc1); }\n",".card-concluida { background: linear-gradient(135deg, #2e7d32, #43a047); }\n","\n",".block-panel {\n","    background: white;\n","    border: 1px solid #dbe8ff;\n","    border-radius: 18px;\n","    box-shadow: 0 8px 24px rgba(26, 73, 140, 0.06);\n","}\n",".section-title {\n","    font-size: 18px;\n","    font-weight: 700;\n","    color: #0d47a1;\n","    margin-bottom: 8px;\n","}\n",".footer-note {\n","    text-align: center;\n","    color: #5f6b7a;\n","    font-size: 13px;\n","    margin-top: 8px;\n","}\n","\"\"\"\n","\n","# =========================================================\n","# INTERFACE\n","# =========================================================\n","validar_estrutura()\n","\n","with gr.Blocks(css=css, theme=gr.themes.Soft(primary_hue=\"blue\", secondary_hue=\"indigo\")) as app:\n","    gr.HTML(\"\"\"\n","        <div class=\"top-banner\">\n","            <h1>TaskFlow SQLite</h1>\n","            <p>Gerencie suas tarefas com uma interface mais bonita, organizada e editável em tempo real.</p>\n","        </div>\n","    \"\"\")\n","\n","    cards_html = gr.HTML(resumo_cards())\n","\n","    with gr.Tabs():\n","        with gr.Tab(\"📋 Painel\"):\n","            with gr.Row():\n","                with gr.Column(scale=1):\n","                    prioridade_filtro = gr.Dropdown(\n","                        choices=[\"Todas\", \"Baixa\", \"Media\", \"Alta\"],\n","                        value=\"Todas\",\n","                        label=\"Prioridade\",\n","                        elem_classes=[\"block-panel\"]\n","                    )\n","                with gr.Column(scale=1):\n","                    status_filtro = gr.Dropdown(\n","                        choices=[\"Todos\", \"Pendente\", \"Em andamento\", \"Concluida\"],\n","                        value=\"Todos\",\n","                        label=\"Status\",\n","                        elem_classes=[\"block-panel\"]\n","                    )\n","                with gr.Column(scale=2):\n","                    texto_filtro = gr.Textbox(\n","                        label=\"Buscar por título ou descrição\",\n","                        placeholder=\"Ex.: reunião, relatório, estudar...\",\n","                        elem_classes=[\"block-panel\"]\n","                    )\n","                with gr.Column(scale=1):\n","                    bt_filtrar = gr.Button(\"Filtrar\", variant=\"primary\")\n","                    bt_recarregar = gr.Button(\"Recarregar\")\n","\n","            tabela = gr.Dataframe(\n","                value=listar_df(),\n","                interactive=False,\n","                wrap=True,\n","                label=\"Tarefas cadastradas\"\n","            )\n","\n","        with gr.Tab(\"➕ Nova tarefa\"):\n","            with gr.Row():\n","                with gr.Column(scale=1, elem_classes=[\"block-panel\"]):\n","                    gr.HTML(\"<div class='section-title'>Cadastrar tarefa</div>\")\n","                    novo_titulo = gr.Textbox(label=\"Título\", placeholder=\"Digite o título da tarefa\")\n","                    novo_desc = gr.Textbox(label=\"Descrição\", lines=5, placeholder=\"Detalhes da tarefa\")\n","                    with gr.Row():\n","                        novo_prio = gr.Dropdown(\n","                            [\"Baixa\", \"Media\", \"Alta\"],\n","                            value=\"Media\",\n","                            label=\"Prioridade\"\n","                        )\n","                        novo_status = gr.Dropdown(\n","                            [\"Pendente\", \"Em andamento\", \"Concluida\"],\n","                            value=\"Pendente\",\n","                            label=\"Status\"\n","                        )\n","                    novo_data = gr.Textbox(\n","                        label=\"Data de vencimento\",\n","                        placeholder=\"dd/mm/yyyy\"\n","                    )\n","\n","                    with gr.Row():\n","                        bt_salvar_novo = gr.Button(\"Salvar tarefa\", variant=\"primary\")\n","                        bt_limpar_novo = gr.Button(\"Limpar\")\n","\n","                    msg_novo = gr.Markdown()\n","\n","        with gr.Tab(\"✏️ Editar / Excluir\"):\n","            with gr.Row():\n","                with gr.Column(scale=1, elem_classes=[\"block-panel\"]):\n","                    gr.HTML(\"<div class='section-title'>Selecionar tarefa</div>\")\n","                    ed_id = gr.Dropdown(\n","                        choices=obter_ids_tarefas(),\n","                        label=\"ID da tarefa\",\n","                        value=None\n","                    )\n","                    bt_carregar = gr.Button(\"Carregar dados\", variant=\"secondary\")\n","\n","                    ed_titulo = gr.Textbox(label=\"Título\")\n","                    ed_desc = gr.Textbox(label=\"Descrição\", lines=5)\n","                    with gr.Row():\n","                        ed_prio = gr.Dropdown(\n","                            [\"Baixa\", \"Media\", \"Alta\"],\n","                            value=\"Media\",\n","                            label=\"Prioridade\"\n","                        )\n","                        ed_status = gr.Dropdown(\n","                            [\"Pendente\", \"Em andamento\", \"Concluida\"],\n","                            value=\"Pendente\",\n","                            label=\"Status\"\n","                        )\n","                    ed_data = gr.Textbox(label=\"Data de vencimento\", placeholder=\"dd/mm/yyyy\")\n","\n","                    with gr.Row():\n","                        bt_atualizar = gr.Button(\"Atualizar tarefa\", variant=\"primary\")\n","                        bt_excluir = gr.Button(\"Excluir tarefa\", variant=\"stop\")\n","                        bt_limpar_ed = gr.Button(\"Limpar\")\n","\n","                    msg_ed = gr.Markdown()\n","\n","    gr.HTML(\"<div class='footer-note'>SQLite + Google Drive + interface visual com Gradio</div>\")\n","\n","    # Eventos painel\n","    bt_filtrar.click(\n","        fn=filtrar_tarefas,\n","        inputs=[prioridade_filtro, status_filtro, texto_filtro],\n","        outputs=[tabela]\n","    )\n","\n","    bt_recarregar.click(\n","        fn=lambda: (listar_df(), resumo_cards(), gr.update(choices=obter_ids_tarefas())),\n","        outputs=[tabela, cards_html, ed_id]\n","    )\n","\n","    # Eventos nova tarefa\n","    bt_salvar_novo.click(\n","        fn=inserir_tarefa,\n","        inputs=[novo_titulo, novo_desc, novo_prio, novo_status, novo_data],\n","        outputs=[msg_novo, tabela, cards_html, ed_id]\n","    )\n","\n","    bt_limpar_novo.click(\n","        fn=limpar_form_novo,\n","        outputs=[novo_titulo, novo_desc, novo_prio, novo_status, novo_data]\n","    )\n","\n","    # Eventos edição\n","    bt_carregar.click(\n","        fn=carregar_tarefa,\n","        inputs=[ed_id],\n","        outputs=[ed_titulo, ed_desc, ed_prio, ed_status, ed_data]\n","    )\n","\n","    bt_atualizar.click(\n","        fn=atualizar_tarefa,\n","        inputs=[ed_id, ed_titulo, ed_desc, ed_prio, ed_status, ed_data],\n","        outputs=[msg_ed, tabela, cards_html, ed_id]\n","    )\n","\n","    bt_excluir.click(\n","        fn=excluir_tarefa,\n","        inputs=[ed_id],\n","        outputs=[msg_ed, tabela, cards_html, ed_id]\n","    )\n","\n","    bt_limpar_ed.click(\n","        fn=limpar_form_edicao,\n","        outputs=[ed_id, ed_titulo, ed_desc, ed_prio, ed_status, ed_data]\n","    )\n","\n","app.launch(share=True, debug=True)"]}]}